parameters.functionCode:
const msg = $input.first().json;
return [{ json: {
  user_id: String(msg.message.from.id),
  chat_id: String(msg.message.chat.id),
  user_input: (msg.message.text || '').replace(/'/g, "''")
} }];

const body = $input.first().json.body;
return [{ json: {
  operation: body.operation || 'search',
  payload: body.payload || {},
  source: 'web'
} }];

const rows = $input.all();
const history = rows.filter(r => r.json && r.json.text).map(r => `Usuario: ${r.json.text}${r.json.response ? '\nAsistente: ' + r.json.response : ''}`).join('\n');
return [{ json: {
  history: history || '(sin historial)',
  user_id: $('Extract Data').item.json.user_id,
  chat_id: $('Extract Data').item.json.chat_id,
  user_input: $('Extract Data').item.json.user_input
} }];

const raw = ($input.first().json.response || '').toLowerCase().trim();
const ctx = $('Prepare Context').item.json;
const txt = ctx.user_input.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

let intent = 'otro';
if (raw.includes('lead_propiedad') || raw.includes('lead')) intent = 'lead_propiedad';
else if (raw.includes('consulta_propiedad') || raw.includes('propiedad')) intent = 'consulta_propiedad';
else if (raw.includes('saludo')) intent = 'saludo';
else if (raw.includes('precio')) intent = 'precio';
else if (raw.includes('soporte')) intent = 'soporte';

if (intent === 'otro' && txt.match(/me interesa|quiero ver|mas info|visita|contacto|interesado/)) intent = 'lead_propiedad';
if (intent === 'otro' && txt.match(/casa|departamento|depto|arriendo|propiedad|vina|serena|santiago|valparaiso|nunoa|providencia|maipu/)) intent = 'consulta_propiedad';

return [{ json: { intent, user_id: ctx.user_id, chat_id: ctx.chat_id, user_input: ctx.user_input, history: ctx.history } }];

