parameters.functionCode:
let raw = $input.first().json.response || '{}';
try {
  const jsonMatch = raw.match(/\{.*\}/s);
  const filters = JSON.parse(jsonMatch ? jsonMatch[0] : '{}');
  return [{ json: { filters } }];
} catch(e) { return [{ json: { filters: {} } }]; }

const ctx = $('Parse Intent').item.json;
const state = $input.first().json;
const msg = ctx.user_input;
let next_step, reply, sql, reply_markup = null;

if (!state || !state.step) {
  next_step = 'comuna';
  reply = '¡Excelente! Iniciemos la búsqueda 🏡\\n\\n¿En qué *comuna* o sector buscas la propiedad?';
  sql = `INSERT INTO user_state (user_id, step) VALUES ('${ctx.user_id}', 'comuna') ON CONFLICT (user_id) DO UPDATE SET step = 'comuna'`;
} else if (state.step === 'comuna') {
  next_step = 'dormitorios';
  reply = `Perfecto, buscaremos en ${msg}. ¿Cuántos *dormitorios* necesitas?`;
  reply_markup = { keyboard: [[{text: '1'}, {text: '2'}], [{text: '3'}, {text: '4+'}], [{text: 'Cualquiera'}]], one_time_keyboard: true, resize_keyboard: true };
  sql = `UPDATE user_state SET step = 'dormitorios', comuna = '${msg}' WHERE user_id = '${ctx.user_id}'`;
} else if (state.step === 'dormitorios') {
  next_step = 'banos';
  reply = 'Entendido. ¿Y cuántos *baños* buscas?';
  reply_markup = { keyboard: [[{text: '1'}, {text: '2'}], [{text: '3+'}], [{text: 'Cualquiera'}]], one_time_keyboard: true, resize_keyboard: true };
  sql = `UPDATE user_state SET step = 'banos', dormitorios = '${msg}' WHERE user_id = '${ctx.user_id}'`;
} else if (state.step === 'banos') {
  next_step = 'done';
  reply = '¡Todo listo! Estoy buscando las mejores opciones para ti... ⏳';
  sql = `UPDATE user_state SET step = 'done', banos = '${msg}' WHERE user_id = '${ctx.user_id}'`;
}

return [{ json: { next_step, reply, reply_markup, sql, user_id: ctx.user_id, chat_id: ctx.chat_id, state } }];
